// Features/Shared/Queries/PagedQueryParameters.cs

public class PagedQueryParameters<T>() where T : class, IEntity
{
    public bool AsNoTracking { get; private set; } = true;

    public bool FilterByKeys { get; private set; }
    public Guid[]? Keys { get; private set; }

    public int? Skip { get; private set; }
    public int? Take { get; private set; }

    // --- Base fluent builders ---

    public PagedQueryParameters<T> WithKeys(params Guid[] keys)
    {
        FilterByKeys = true;
        Keys = keys;
        return this;
    }

    public PagedQueryParameters<T> WithPagination(int skip, int take)
    {
        Skip = skip;
        Take = take;
        return this;
    }

    public PagedQueryParameters<T> WithTracking()
    {
        AsNoTracking = false;
        return this;
    }

    // --- Query application methods ---

    public virtual IQueryable<T> ApplyFilters(IQueryable<T> query)
    {
        if (AsNoTracking)
            query = query.AsNoTracking();

        if (FilterByKeys && Keys is { Length: > 0 })
            query = query.Where(e => Keys.Contains(e.Id));

        return query;
    }

    public IQueryable<T> ApplyPagination(IQueryable<T> query)
    {
        if (Skip.HasValue)
            query = query.Skip(Skip.Value);
        if (Take.HasValue)
            query = query.Take(Take.Value);
        return query;
    }

    protected static string EscapeILike(string s) =>
        s.Replace("\\", "\\\\").Replace("%", "\\%").Replace("_", "\\_");
}

