// Features/Actions/Shared/Queries/ActionQueryParameters.cs

public class ActionQueryParameters : PagedQueryParameters<ActionEntity>
{
    public string? SearchTerm { get; private set; }
    public string? StatusFilter { get; private set; }

    public ActionQueryParameters WithSearch(string? search)
    {
        if (!string.IsNullOrWhiteSpace(search))
            SearchTerm = search;
        return this;
    }

    public ActionQueryParameters WithStatus(string? status)
    {
        if (!string.IsNullOrWhiteSpace(status))
            StatusFilter = status;
        return this;
    }

    public IQueryable<ActionEntity> IncludeRelations(IQueryable<ActionEntity> query)
    {
        return query
            .Include(a => a.WorkflowSteps)
            .Include(a => a.Triggers);
    }

    public override IQueryable<ActionEntity> ApplyFilters(IQueryable<ActionEntity> query)
    {
        query = base.ApplyFilters(query);

        if (!string.IsNullOrWhiteSpace(SearchTerm))
        {
            var escaped = EscapeILike(SearchTerm);
            query = query.Where(a => EF.Functions.ILike(a.Name, $"%{escaped}%")
                                  || EF.Functions.ILike(a.Slug, $"%{escaped}%"));
        }

        if (!string.IsNullOrWhiteSpace(StatusFilter))
            query = query.Where(a => a.Status == StatusFilter);

        return query;
    }
}

