public class WorkflowQueryParameters : PagedQueryParameters<Workflow>
{
    public string? SearchTerm { get; private set; }
    public Guid? ActionId { get; private set; }
    public string? TriggerType { get; private set; }

    public WorkflowQueryParameters WithSearch(string? search)
    {
        if (!string.IsNullOrWhiteSpace(search))
            SearchTerm = search;
        return this;
    }

    public WorkflowQueryParameters WithAction(Guid? actionId)
    {
        ActionId = actionId;
        return this;
    }

    public WorkflowQueryParameters WithTriggerType(string? triggerType)
    {
        if (!string.IsNullOrEmpty(triggerType))
            TriggerType = triggerType;
        return this;
    }

    public IQueryable<Workflow> IncludeRelations(IQueryable<Workflow> query)
    {
        return query
            .Include(w => w.Action)
            .Include(w => w.Steps)
                .ThenInclude(s => s.StepActions);
    }

    public override IQueryable<Workflow> ApplyFilters(IQueryable<Workflow> query)
    {
        query = base.ApplyFilters(query);

        if (ActionId.HasValue)
            query = query.Where(w => w.ActionId == ActionId.Value);

        if (!string.IsNullOrEmpty(TriggerType))
            query = query.Where(w => w.Triggers.Any(t => t.TriggerType == TriggerType));

        if (!string.IsNullOrWhiteSpace(SearchTerm))
        {
            var escaped = EscapeILike(SearchTerm);
            query = query.Where(w => EF.Functions.ILike(w.Name, $"%{escaped}%"));
        }

        return query;
    }
}

